You set a breakpoint on line 8 (`int y = square(x);`). The debugger pauses. You look at the variables panel. What is the value of `y` at this moment?

```cpp
#include <iostream>

int square(int n) {
    return n * n;
}

int main() {
    int x = 4;
    int y = square(x);  // breakpoint here (line 8)
    std::cout << y << "\n";
    return 0;
}
```

A developer uses `std::cerr` to simulate where they would place a breakpoint. What does this program print to **stdout**?

```cpp
#include <iostream>

int halve(int n) {
    std::cerr << "[bp] halve n=" << n << "\n";
    return n / 2;
}

int main() {
    int a = halve(12);
    int b = halve(a);
    std::cout << b << "\n";
    return 0;
}
```

What does this program print to **stdout**?

```cpp
#include <iostream>

int add(int a, int b) {
    return a + b;
}

int main() {
    int x = add(3, 7);
    std::cerr << "[debug] x=" << x << "\n";
    int y = add(x, 5);
    std::cerr << "[debug] y=" << y << "\n";
    std::cout << y << "\n";
    return 0;
}
```
